import fs from 'node:fs';
import path from 'node:path';
export function runtimeConfigFromEnv(env = process.env) {
    const daemonPort = Number.parseInt(env.AGENT_ORB_DAEMON_PORT ?? '17321', 10);
    if (!Number.isInteger(daemonPort) || daemonPort <= 0 || daemonPort > 65535) {
        throw new Error(`Invalid AGENT_ORB_DAEMON_PORT: ${env.AGENT_ORB_DAEMON_PORT}`);
    }
    return {
        daemonHost: env.AGENT_ORB_DAEMON_HOST ?? '127.0.0.1',
        daemonPort,
    };
}
export function writeConfig(configDir, selectedAdapters, runtime = runtimeConfigFromEnv()) {
    fs.mkdirSync(configDir, { recursive: true });
    const configPath = path.join(configDir, 'config.toml');
    const byName = new Map(selectedAdapters.map((adapter) => [adapter.name, adapter]));
    const enabled = (name) => byName.has(name);
    // Persist the resolved binary path so the config matches the generated shim
    // and `doctor` can report the real target instead of a bare command name.
    const binaryOf = (name) => tomlEscape(byName.get(name)?.foundBinary ?? name);
    const content = `# Generated by npx agent_orb\n\n[install]\nmethod = "npx"\nversion = "0.1.18"\n\n[adapters.codex]\nenabled = ${enabled('codex')}\nbinary = "${binaryOf('codex')}"\nwrapper = "agent_orb-codex"\n\n[adapters.claude]\nenabled = ${enabled('claude')}\nbinary = "${binaryOf('claude')}"\nwrapper = "agent_orb-claude"\n\n[daemon]\nhost = "${runtime.daemonHost}"\nport = ${runtime.daemonPort}\nauto_start = true\n\n[orb]\nposition = "top-right"\nsize = 48\nopacity = 0.92\nalways_on_top = true\nclick_through = false\n\n[colors]\ndisconnected = "#6B7280"\nidle = "#9CA3AF"\nstarting = "#60A5FA"\nactive = "#3B82F6"\nthinking_like = "#FACC15"\nwaiting_input = "#EF4444"\ncompacting = "#A855F7"\ncompleted = "#22C55E"\nerror = "#EF4444"\nwarning = "#F97316"\n\n[behavior]\nsilent_threshold_seconds = 20\nstuck_threshold_seconds = 180\ncompleted_hold_seconds = 10\nerror_requires_click_to_clear = true\n\n[privacy]\ninclude_output_sample = false\nmax_sample_chars = 512\n`;
    fs.writeFileSync(configPath, content, 'utf8');
    return configPath;
}
// Escape backslashes and quotes so Windows paths survive TOML double-quoted strings.
function tomlEscape(value) {
    return value.replace(/\\/g, '\\\\').replace(/"/g, '\\"');
}
